#include <string>
using namespace std;

string convertToBase(long long num, int base) {
    if (num == 0) return "0";
    string res;
    while (num > 0) {
        int rem = num % base;
        char c;
        if (rem < 10) {
            c = '0' + rem;
        } else {
            c = 'A' + rem - 10;
        }
        res.insert(0, 1, c);
        num = num / base;
    }
    return res;
}

string solve(long long n) {
    long long n2 = n * n;
    long long n3 = n * n * n;
    string hex_part = convertToBase(n2, 16);
    string base36_part = convertToBase(n3, 36);
    return hex_part + base36_part;
}

